#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
int n,m,s[60][405],top[60],t[60][2];
int x[820001],y[820001],tot=0;
inline void move(int a,int b){s[b][++s[b][0]]=s[a][s[a][0]--];x[++tot]=a,y[tot]=b;}
inline void cnt(int x,int mid){t[x][0]=t[x][1]=0;rep(1,m,i)t[x][s[x][i]>mid]++;}
inline long long read()
{
	long long ans=0;bool f=0;char ch=getchar();
	while(ch<'0'||ch>'9'){if(ch=='-')f=1;ch=getchar();}
	while(ch>='0'&&ch<='9'){ans=(ans<<1)+(ans<<3)+(ch^48);ch=getchar();}
	if(f) return -ans; return ans;
}
inline void input(){n=read();m=read();rep(1,n,i)rep(1,m,j)s[i][j]=read(),s[i][0]=m;}
inline void solve(int l,int r)
{
	if(l==r)return;int mid=(l+r)>>1;int x=l,y=mid+1;
	rep(l,r,i)cnt(i,mid);while(x<=r)
	{
		y=x!=l?l:r;
		rep(1,t[x][1],i)move(y,n+1);
		while(s[x][0]!=0)if(s[x][s[x][0]]>mid)move(x,y);else move(x,n+1);
		rep(1,t[x][0],i)move(n+1,x);
		rep(1,t[x][1],i)move(y,x);
		rep(1,t[x][1],i)move(n+1,y);
		cnt(x,mid);cnt(y,mid);x++;
	}
	x=l,y=mid+1;while(x<=mid)
	{
		if(t[x][0]+t[y][0]==m)
		{
			rep(1,t[x][1],i)move(x,n+1);rep(1,t[y][1],i)move(y,n+1);
			rep(1,t[y][0],i)move(y,x);rep(1,m,i)move(n+1,y);
			cnt(x,mid);cnt(y,mid);x++;y++;
		}
		else if(t[x][0]+t[y][0]>m)
		{
			rep(1,t[x][1],i)move(x,n+1);
			rep(1,t[y][1],i)move(y,n+1);
			rep(1,t[x][1],i)move(y,x);
			rep(1,t[x][1]+t[y][1],i)move(n+1,y);
			cnt(x,mid);cnt(y,mid);x++;
		}
		else{
			rep(1,m,i)move(y,n+1);
			rep(1,t[x][1],i)move(x,y);
			rep(1,t[x][1],i)move(n+1,x);
			rep(1,t[x][0],i)move(n+1,y);
			cnt(x,mid);cnt(y,mid);y++;
		}
	}
	solve(l,mid);solve(mid+1,r);
}
inline void print(){printf("%d\n",tot);rep(1,tot,i)printf("%d %d\n",x[i],y[i]);}
int main(){input();solve(1,n);print();}
